const Dev1 = "ASSET"
const Dev2 = "ASSET"
const Dev3 = "ASSET"

const scaleBy1000 = [4200, 4300]
const ids = [4200, 4300, 4600, 4500]

const HEADER_LEN = 3

var buf = (typeof msg.payload === "string")
    ? Buffer.from(msg.payload, "base64")
    : msg.payload

if (!Buffer.isBuffer(buf) || buf.length < HEADER_LEN + 4) {
    node.error("Invalid payload - te kort", msg)
    return null
}

function readF(off) {
    if (off + 4 > buf.length) return null
    const v = buf.readFloatBE(off)
    if (isNaN(v)) return null
    return Math.round(v * 100) / 100
}

const battery = (((buf[0] << 8) | buf[1]) & 0x7fff) / 1000

// 12 floats uitlezen, graceful bij kortere buffer
const values = []
for (let i = 0; i < 12; i++) {
    const off = HEADER_LEN + i * 4
    if (off + 4 > buf.length) {
        values.push(null)
    } else {
        values.push(readF(off))
    }
}

function buildDevice(dev, vals) {
    const d = {
        Dev: dev,
        ED: [],
        MD: []
    }

    for (let i = 0; i < ids.length; i++) {
        let val = vals[i]
        if (val != null) {
            if (scaleBy1000.includes(ids[i])) {
                val = Math.round((val / 1000) * 1000) / 1000
            }
            d.MD.push({ Id: ids[i], Val: val })
        }
    }

    d.MD.push({ Id: 7200, Val: battery })

    if (msg.snr !== undefined)
        d.MD.push({ Id: 5400, Val: parseFloat(msg.snr) })
    if (msg.rssi !== undefined)
        d.MD.push({ Id: 5500, Val: parseFloat(msg.rssi) })
    if (msg.dr?.spreadFactor !== undefined)
        d.MD.push({ Id: 5200, Val: parseFloat(msg.dr.spreadFactor) })

    d.TS = msg.time ? new Date(msg.time).toISOString() : new Date().toISOString()
    return d
}

const mid = global.get("mid") || 0
let midOffset = 0

const out1 = values.slice(0, 4).some(v => v !== null)
    ? { ...msg, payload: { MID: mid + midOffset++, D: [buildDevice(Dev1, values.slice(0, 4))] } }
    : null

const out2 = values.slice(4, 8).some(v => v !== null)
    ? { ...msg, payload: { MID: mid + midOffset++, D: [buildDevice(Dev2, values.slice(4, 8))] } }
    : null

const out3 = values.slice(8, 12).some(v => v !== null)
    ? { ...msg, payload: { MID: mid + midOffset++, D: [buildDevice(Dev3, values.slice(8, 12))] } }
    : null

if (!out1) node.warn(`CH01 geen data - ${Dev1}`)
if (!out2) node.warn(`CH02 geen data - ${Dev2}`)
if (!out3) node.warn(`CH03 geen data - ${Dev3}`)

global.set("mid", mid + midOffset)

return [out1, out2, out3]
